1	function [pairedUEs, precoder, pairedUEsMcs] = nrSelectPairedUEsSRS(schedulerInput, muMIMOConfigDL, selectedUE, mumimoUEs)
2	%nrSelectPairedUEsSRS User pairing for SRS-based downlink MU-MIMO.
3	%
4	%   Note: This is an internal undocumented function and its API and/or
5	%   functionality may change in subsequent releases.
6	%
7	%   [PAIREDUES, PRECODER, PAIREDUESMCS] = nr5g.internal.nrSelectPairedUEsSRS(...
8	%   SCHEDULERINPUT, MUMIMOCONFIGDL, SELECTEDUE, MUMIMOUEs) returns the
9	%   paired UEs, the corresponding precoding matrices, and the MCS for
10	%   each paired UE.
11	%
12	%   SCHEDULERINPUT structure contains the fields which scheduler
13	%   needs for selecting the UE for resource allocation.
14	%
15	%   MUMIMOCONFIGDL structure contains the constraints that the user pairing
16	%   algorithm needs for determining the MU-MIMO candidacy among UEs.
17	%
18	%   SELECTEDUE is the RNTI of the initially selected UE.
19	%
20	%   MUMIMOUES contains an array of UEs available for MU-MIMO pairing.
21	%
22	%   PAIREDUES contains the list of RNTIs of the UEs selected for pairing.
23	%
24	%   PRECODER cell array contains the precoding matrices for the paired UEs.
25	%
26	%   PAIREDUESMCS contains an array of MCS indices for each paired UE. It
27	%   also contains primary UE's MCS.
28	
29	%   Copyright 2024 The MathWorks, Inc.
30	
31	% Reference
32	% [1] K. Ko and J. Lee, "Determinant Based Multiuser MIMO Scheduling with
33	% Reduced Pilot Overhead," 2011 IEEE 73rd Vehicular Technology Conference
34	% (VTC Spring), Budapest, Hungary, 2011.
35	
36	% User configurable constraints MaxNumUsersPaired and MaxNumLayers are used
37	% to limit the number of paired UEs.
38	maxNumUsersPaired = muMIMOConfigDL.MaxNumUsersPaired;
39	maxNumLayers = muMIMOConfigDL.MaxNumLayers;
40	
41	% Extract the rank-reduced wideband channel matrices and noise variance
42	H = schedulerInput.channelMatrix;
43	nVar = schedulerInput.nVar;
44	% Number of transmit antennas at gNB
45	M = size(H{selectedUE == schedulerInput.eligibleUEs}, 2);
46	
47	% Initialize paired UEs with the primary selected UE
48	pairedUEs = selectedUE;
49	pairedUEsMcs = schedulerInput.mcsRBG(schedulerInput.eligibleUEs == pairedUEs, 1);
50	precoder = schedulerInput.W(schedulerInput.eligibleUEs == pairedUEs);
51	
52	remainingUEs = mumimoUEs;
53	if remainingUEs
54	    % Initialize the combined channel matrix of the selected UEs with the
55	    % primary UE's channel matrix
56	    HSelectedSet = H{selectedUE == schedulerInput.eligibleUEs};
57	
58	    % Compute initial sum rate, precoding matrix, and post MMSE equalized
59	    % SINRs.
60	    [sumRate, precoder, sinr] = computeSumRate(H(selectedUE == schedulerInput.eligibleUEs), nVar);
61	
62	    % Initialize orthogonal projection matrix
63	    X = eye(M) - HSelectedSet' / (HSelectedSet * HSelectedSet') * HSelectedSet;
64	
65	    % Iteratively select additional UEs for pairing
66	    for i = 1:maxNumUsersPaired-1
67	        bestUser = selectedUE;
68	        selectedDet = -Inf;
69	        % Evaluate each potential UE in the remaining UEs set for pairing
70	        for n = remainingUEs
71	            Hn = H{n == schedulerInput.eligibleUEs};
72	            detValue = det(Hn * X * Hn');
73	            if detValue > selectedDet
74	                selectedDet = detValue;
75	                bestUser = n;
76	            end
77	        end
78	        % Attempt to add the best user to the current set
79	        pairedUEsTemp = union(pairedUEs, bestUser, "stable");
80	        % Check if maximum number of layers has been exceeded
81	        if size(HSelectedSet, 1) >= maxNumLayers
82	            break;
83	        end
84	        chanIndex = arrayfun(@(m) find(schedulerInput.eligibleUEs == m, 1), pairedUEsTemp);
85	        [sumRateTemp, precoderTemp, sinrTemp] = computeSumRate(H(chanIndex), nVar);
86	
87	        % Check if adding the user improves sum rate
88	        if sumRateTemp <= sumRate
89	            break;
90	        else
91	            % Update the combined channel matrix by concatenating the channel
92	            % matrix of the newly selected UE.
93	            HSelectedSet = cat(2, HSelectedSet.', H{bestUser == schedulerInput.eligibleUEs}.').';
94	            % Update the projection matrix X, the paired UEs set, sum rate,
95	            % precoding matrices, SINR, and the remaining UEs set after
96	            % successful pairing.
97	            X = eye(M) - HSelectedSet' / (HSelectedSet * HSelectedSet') * HSelectedSet;
98	            pairedUEs = pairedUEsTemp;
99	            sumRate = sumRateTemp;
100	            precoder = precoderTemp;
101	            sinr = sinrTemp;
102	            remainingUEs(remainingUEs == bestUser) = [];
103	        end
104	    end
105	end
106	
107	% If the paired list contains just the primary UE, reuse the SU-MIMO precoder and MCS
108	if ~isscalar(pairedUEs)
109	    % Initialize carrier and PDSCH configuration for MCS computation
110	    carrier = nrCarrierConfig;
111	    carrier.NSizeGrid = size(schedulerInput.channelQuality, 2);
112	    l2smSRS = nr5g.internal.L2SM.initialize(carrier);
113	    pdschConfig = nrPDSCHConfig;
114	    pdschConfig.PRBSet = (0:carrier.NSizeGrid-1);
115	    pdschConfig.DMRS.DMRSPortSet = [];
116	    % Compute MCS for each paired UE
117	    pairedUElength = numel(pairedUEs);
118	    pairedUEsMcs = zeros(pairedUElength, 1);
119	    k = 1;
120	    for i = 1:pairedUElength
121	        numLayers = size(precoder{i}, 1);
122	        sinrPerUELayers = sinr(k:k+numLayers-1);
123	        pdschConfig.NumLayers = numLayers;
124	        pairedUEsMcs(i) = nr5g.internal.computeMCS(l2smSRS, carrier, pdschConfig, sinrPerUELayers, 'qam256');
125	        k = k + numLayers;
126	    end
127	end
128	end
