130	function [R, W, sinr] = computeSumRate(H, nVar)
131	%computeSumRate computes the sum rate, precoder matrices, and SINR.
132	%
133	%   [R, W, SINR] = computeSumRateSLS(H, NVAR) returns the sum rate,
134	%   precoding matrices computed using block diagonalization (BD), and SINR
135	%   for a given set of channel matrices and noise variance.
136	%
137	%   H is a cell array of channel matrices for each UE.
138	%   NVAR is the noise variance.
139	%
140	%   R is the computed sum rate.
141	%   W is a cell array of precoding matrices for each UE.
142	%   SINR is the post MMSE equalized Signal-to-Interference-plus-Noise
143	%   Ratio for each layer.
144	
145	% Get the umber of UEs
146	K = numel(H);
147	
148	% Compute block diagonal beamforming weights
149	ns = cellfun(@(x) size(x, 1), H)';
150	Hcell = cellfun(@transpose, H, 'UniformOutput', false);

150	Hcell = cellfun(@transpose, H, 'UniformOutput', false);
151	Wg = blkdiagbfweights(Hcell, ns);
152	
153	% Preallocate the cell array W for beamforming weights
154	W = cell(1, K);
155	
156	% Extract the precoding matrices per UE from the combined block diagonal
157	% beamforming weights, Wg
158	startIdx = 1;
159	for k = 1:K
160	    N = ns(k);
161	    W{k} = normalizeMatrix(Wg(startIdx:startIdx+N-1, :), N);
162	    startIdx = startIdx + N;
163	end
164	
165	% Concatenate channel matrices to form the combined channel matrix
166	Htot = [Hcell{:}];
167	V = Wg.';
168	
169	% Compute post MMSE equalized SINR by using the precoded channel matrix
170	sinr = nr5g.internal.nrPrecodedSINR(Htot.', nVar, V);
171	
172	% Compute the sum rate using the SINR values
173	R = sum(log2(1 + sinr));
174	end
